import React, { useState } from 'react';
import { supabase } from '../services/supabase';

const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [agencyName, setAgencyName] = useState('');

  const [loading, setLoading] = useState(false);
  const [isSignUp, setIsSignUp] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [message, setMessage] = useState<string | null>(null);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setMessage(null);

    try {
      if (isSignUp) {
        // Sign Up with metadata to trigger the profile creation function if available
        const { data, error: authError } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: {
              full_name: fullName,
              agency_name: agencyName,
            }
          }
        });
        if (authError) throw authError;

        // Manual fallback if trigger is not set
        if (data.user) {
          await supabase.from('profiles').upsert({
            id: data.user.id,
            full_name: fullName,
            agency_name: agencyName,
            updated_at: new Date()
          });
        }

        setMessage('Conta Premium criada! Verifique seu e-mail para confirmar o acesso total.');
      } else {
        const { error: signInError } = await supabase.auth.signInWithPassword({
          email,
          password,
        });
        if (signInError) throw signInError;
      }
    } catch (err: any) {
      setError(err.message || 'Ocorreu um erro. Verifique seus dados.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen w-full flex items-center justify-center bg-[#0f172a] relative overflow-hidden">
      {/* Background Decorative Elements */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/20 rounded-full blur-[120px] animate-pulse"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-indigo-600/20 rounded-full blur-[120px] animate-pulse delay-700"></div>

      <div className="w-full max-w-[440px] px-6 py-12 relative z-10">
        <div className="bg-white/10 backdrop-blur-xl border border-white/10 rounded-[32px] p-8 md:p-10 shadow-2xl">

          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-gradient-to-tr from-blue-600 to-indigo-500 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-2xl shadow-blue-500/30">
              <span className="text-white text-3xl font-bold tracking-tighter">CT</span>
            </div>
            <h1 className="text-3xl font-bold text-white tracking-tight">Copy Travel</h1>
            <p className="text-slate-400 mt-3 text-sm font-medium">
              {isSignUp ? 'Inicie sua jornada Premium agora.' : 'Bem-vindo de volta ao seu QG de vendas.'}
            </p>
          </div>

          <form onSubmit={handleAuth} className="space-y-5">
            {isSignUp && (
              <div className="space-y-4 animate-in fade-in slide-in-from-top-4 duration-500">
                <div className="relative group">
                  <input
                    type="text"
                    value={fullName}
                    onChange={(e) => setFullName(e.target.value)}
                    required
                    className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white placeholder-slate-500 outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition-all"
                    placeholder="Seu nome completo"
                  />
                </div>
                <div className="relative group">
                  <input
                    type="text"
                    value={agencyName}
                    onChange={(e) => setAgencyName(e.target.value)}
                    required
                    className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white placeholder-slate-500 outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition-all"
                    placeholder="Nome da sua Agência"
                  />
                </div>
              </div>
            )}

            <div className="relative">
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white placeholder-slate-500 outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition-all"
                placeholder="E-mail profissional"
              />
            </div>

            <div className="relative">
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white placeholder-slate-500 outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition-all"
                placeholder="Sua senha secreta"
              />
            </div>

            {error && (
              <div className="p-4 bg-red-500/10 border border-red-500/20 text-red-400 text-xs rounded-2xl animate-shake">
                {error}
              </div>
            )}

            {message && (
              <div className="p-4 bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 text-xs rounded-2xl">
                {message}
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-2xl transition-all shadow-xl shadow-blue-600/20 active:scale-[0.98] disabled:opacity-50 flex items-center justify-center gap-3 mt-4"
            >
              {loading ? (
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
              ) : (
                <>
                  <span>{isSignUp ? 'Liberar Acesso Premium' : 'Entrar na Plataforma'}</span>
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
                </>
              )}
            </button>
          </form>

          <div className="mt-8 text-center">
            <button
              onClick={() => { setIsSignUp(!isSignUp); setError(null); setMessage(null); }}
              className="text-slate-400 hover:text-white text-sm font-medium transition-colors underline-offset-4 hover:underline"
            >
              {isSignUp ? 'Já possui acesso VIP? Faça login' : 'Ainda não é Premium? Cadastre-se agora'}
            </button>
          </div>
        </div>

        <p className="text-center text-slate-600 text-[11px] mt-8 uppercase tracking-widest font-bold">
          © Copy Travel Premium • Acesso Vitalício Liberado
        </p>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import ChatInterface from './components/SalesGenerator';
import TemplateLibrary from './components/TemplateLibrary';
import Settings from './components/Settings';
import Login from './components/Login';
import { ChatSession, Message, GeneratedOption, AppView, UserProfile } from './types';
import { supabase } from './services/supabase';

const LOCAL_STORAGE_KEY = 'copytravel_premium_sessions';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [isAuthChecking, setIsAuthChecking] = useState(true);
  const [currentView, setCurrentView] = useState<AppView>('chat');
  const [darkMode, setDarkMode] = useState(true); // Default to Dark Premium

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setIsAuthChecking(false);
      if (session) fetchUserProfile(session.user.id);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) fetchUserProfile(session.user.id);
      else setUserProfile(null);
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchUserProfile = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (data) setUserProfile(data);
    } catch (error) {
      console.warn("Profile syncing...");
    }
  };

  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(sessions));
    }
  }, [sessions]);

  useEffect(() => {
    if (!isAuthChecking) {
      if (session) {
        loadSessionsFromSupabase();
      } else {
        const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
        if (saved) {
          try {
            const parsed = JSON.parse(saved);
            if (parsed.length > 0) {
              setSessions(parsed);
              return;
            }
          } catch(e) {}
        }
      }
    }
  }, [session, isAuthChecking]);

  const loadSessionsFromSupabase = async () => {
    try {
      const { data, error } = await supabase
        .from('chat_sessions')
        .select('*')
        .eq('user_id', session.user.id)
        .order('last_modified', { ascending: false });

      if (data && data.length > 0) {
        setSessions(data);
        if (!currentSessionId) setCurrentSessionId(data[0].id);
      } else {
        createNewChat();
      }
    } catch (error) {
      createNewChat();
    }
  };

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: crypto.randomUUID(),
      title: 'Nova Estratégia',
      messages: [],
      lastModified: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setCurrentView('chat');
    if (window.innerWidth < 768) setIsSidebarOpen(false);

    if (session) {
      supabase.from('chat_sessions').insert({
        id: newSession.id,
        user_id: session.user.id,
        title: newSession.title,
        messages: newSession.messages,
        last_modified: newSession.lastModified
      }).then();
    }
  };

  const updateCurrentSession = (text: string, role: 'user' | 'model', options?: GeneratedOption[]) => {
    if (!currentSessionId) return;

    setSessions(prevSessions => {
      return prevSessions.map(s => {
        if (s.id === currentSessionId) {
          const newMsg: Message = {
            id: Math.random().toString(36).substr(2, 9),
            role,
            content: text,
            options,
            timestamp: Date.now()
          };

          let newTitle = s.title;
          if (s.messages.length === 0 && role === 'user') {
            newTitle = text.length > 30 ? text.substring(0, 30) + '...' : text;
          }

          const updated = {
            ...s,
            title: newTitle,
            messages: [...s.messages, newMsg],
            lastModified: Date.now()
          };

          if (session) {
            supabase.from('chat_sessions').upsert({
              id: updated.id,
              user_id: session.user.id,
              title: updated.title,
              messages: updated.messages,
              last_modified: updated.lastModified
            }).then();
          }

          return updated;
        }
        return s;
      });
    });
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setSessions([]);
    setCurrentSessionId(null);
    setUserProfile(null);
  };

  if (isAuthChecking) return <div className="h-screen w-full flex items-center justify-center bg-[#0f172a] text-blue-400 font-bold animate-pulse">COPY TRAVEL PREMIUM...</div>;
  if (!session) return <Login />;

  const currentSession = sessions.find(s => s.id === currentSessionId);

  return (
    <div className={`${darkMode ? 'dark' : ''} flex h-screen w-full bg-slate-900 text-white overflow-hidden`}>
      {isSidebarOpen && <div className="fixed inset-0 bg-black/60 z-20 md:hidden" onClick={() => setIsSidebarOpen(false)} />}

      <aside className={`fixed md:relative z-30 w-[280px] h-full bg-slate-950 border-r border-white/5 transform transition-transform duration-300 flex flex-col ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0 md:w-0 overflow-hidden'}`}>
        <div className="p-6 flex items-center justify-between">
           <div className="flex items-center gap-3">
             <div className="w-9 h-9 rounded-xl bg-blue-600 flex items-center justify-center shadow-lg shadow-blue-600/20">
               <span className="text-white font-black text-sm">CT</span>
             </div>
             <div>
               <span className="font-bold text-white block leading-none">Copy Travel</span>
               <span className="text-[10px] text-blue-400 font-black uppercase tracking-tighter">Premium VIP</span>
             </div>
           </div>
        </div>

        <div className="px-4 pb-4 space-y-2">
          <button onClick={createNewChat} className="w-full flex items-center gap-3 px-4 py-3 text-sm bg-blue-600 hover:bg-blue-500 text-white rounded-xl transition-all font-bold shadow-lg shadow-blue-600/10">
            <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" /></svg>
            Nova Estratégia
          </button>

          <button onClick={() => { setCurrentView('library'); if(window.innerWidth < 768) setIsSidebarOpen(false); }} className={`w-full flex items-center gap-3 px-4 py-3 text-sm rounded-xl transition-all font-bold ${currentView === 'library' ? 'bg-white/10 text-white' : 'text-slate-400 hover:bg-white/5'}`}>
            <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
            Biblioteca de Scripts
          </button>
        </div>

        <div className="flex-1 overflow-y-auto px-4 py-2 space-y-1 scrollbar-thin">
          <div className="px-2 text-[10px] font-black text-slate-500 uppercase tracking-[2px] mb-3 mt-4">Suas Negociações</div>
          {sessions.map(s => (
            <div key={s.id} onClick={() => { setCurrentSessionId(s.id); setCurrentView('chat'); if(window.innerWidth < 768) setIsSidebarOpen(false); }} className={`group flex items-center justify-between px-4 py-3 rounded-xl cursor-pointer transition-all ${currentSessionId === s.id && currentView === 'chat' ? 'bg-white/10 text-white ring-1 ring-white/10' : 'text-slate-400 hover:bg-white/5'}`}>
              <span className="text-sm truncate font-medium">{s.title}</span>
            </div>
          ))}
        </div>

        <div className="p-4 border-t border-white/5 bg-slate-950">
           <div className="flex items-center justify-between bg-white/5 p-3 rounded-2xl border border-white/5">
             <div className="flex flex-col min-w-0">
                <button onClick={() => { setCurrentView('settings'); if(window.innerWidth < 768) setIsSidebarOpen(false); }} className="text-xs font-bold text-white truncate hover:text-blue-400 text-left transition-colors">
                  {userProfile?.full_name || session.user.email}
                </button>
                <button onClick={handleLogout} className="text-[10px] text-slate-500 hover:text-red-400 text-left mt-0.5 font-bold uppercase tracking-wider">Desconectar</button>
             </div>
             <button onClick={() => setCurrentView('settings')} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all">
                <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37a1.724 1.724 0 002.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
             </button>
           </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full bg-slate-900 overflow-hidden relative">
        <header className="md:hidden p-4 border-b border-white/5 flex items-center justify-between">
           <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-white/5 rounded-xl border border-white/10">
             <svg className="h-6 w-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" /></svg>
           </button>
           <span className="font-black text-xs uppercase tracking-[3px] text-blue-400">Premium</span>
        </header>

        {currentView === 'settings' ? (
          <Settings session={session} userProfile={userProfile} onProfileUpdate={setUserProfile} />
        ) : currentView === 'library' ? (
          <TemplateLibrary />
        ) : currentSession ? (
          <ChatInterface 
            messages={currentSession.messages} 
            onSendMessage={updateCurrentSession}
            isLoading={isLoading}
            setLoading={setIsLoading}
            userProfile={userProfile}
          />
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-center p-8">
             <div className="w-24 h-24 bg-blue-600/10 rounded-full flex items-center justify-center mb-6">
                <svg className="h-12 w-12 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" /></svg>
             </div>
             <h2 className="text-2xl font-bold mb-2">Pronto para fechar?</h2>
             <p className="text-slate-400 mb-8 max-w-sm">Seu assistente de vendas de elite está pronto para converter qualquer cliente em passageiro.</p>
             <button onClick={createNewChat} className="px-8 py-4 bg-blue-600 hover:bg-blue-500 text-white font-black rounded-2xl shadow-xl shadow-blue-600/20 transition-all uppercase tracking-widest text-sm">Iniciar Nova Venda</button>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedOption, Message, UserProfile } from "../types";

const apiKey = process.env.API_KEY;
const ai = new GoogleGenAI({ apiKey: apiKey || '' });

export const generateChatResponse = async (
  currentInput: string,
  history: Message[],
  userProfile?: UserProfile | null
): Promise<{ text: string; options: GeneratedOption[] }> => {

  const conversationContext = history
    .map(msg => `${msg.role === 'user' ? 'Agente' : 'Copy Travel'}: ${msg.content}`)
    .join('\n');

  const agentIdentity = userProfile 
    ? `Você é o estrategista de vendas de ${userProfile.full_name || 'um agente'} da agência ${userProfile.agency_name || 'Premium'}.` 
    : 'Você é um estrategista de vendas de elite (Top 1% Brasil).';

  const prompt = `
    ${agentIdentity}
    Sua missão é fornecer scripts de WhatsApp extremamente persuasivos e naturais para fechar vendas de turismo.

    MODO PREMIUM ATIVADO: 
    - Use técnicas avançadas de PNL e Gatilhos Mentais.
    - Foque em manter o controle da negociação.
    - Estilo: Curto, direto, sem emojis excessivos, profissional mas amigável.
    - Sempre termine com uma pergunta poderosa de fechamento ou avanço.

    CONTEXTO ATUAL:
    ${conversationContext}

    ÚLTIMA FALA DO CLIENTE (enviada pelo Agente):
    "${currentInput}"

    Gere 3 opções estratégicas de resposta.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Upgrade para o modelo Pro para raciocínio superior
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            analysis: { type: Type.STRING },
            options: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  content: { type: Type.STRING },
                  technique: { type: Type.STRING },
                  rationale: { type: Type.STRING },
                  branches: {
                    type: Type.OBJECT,
                    properties: {
                      positive: { type: Type.STRING },
                      negative: { type: Type.STRING }
                    },
                    required: ["positive", "negative"]
                  }
                },
                required: ["content", "technique", "rationale", "branches"]
              }
            }
          }
        }
      }
    });

    const result = JSON.parse(response.text || "{}");
    return {
      text: result.analysis || "Análise da negociação:",
      options: result.options || []
    };

  } catch (error) {
    console.error("AI Error:", error);
    return { text: "Erro na conexão Premium. Tente novamente.", options: [] };
  }
};

import React, { useState, useEffect } from 'react';
import ChatInterface from './components/SalesGenerator';
import TemplateLibrary from './components/TemplateLibrary';
import Settings from './components/Settings';
import { ChatSession, Message, GeneratedOption, AppView, UserProfile } from './types';
import { supabase } from './services/supabase';

const LOCAL_STORAGE_KEY = 'copytravel_premium_sessions';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [isAuthChecking, setIsAuthChecking] = useState(true);
  const [currentView, setCurrentView] = useState<AppView>('chat');
  const [darkMode, setDarkMode] = useState(true);

  // Monitorar Autenticação (Opcional agora)
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setIsAuthChecking(false);
      if (session) fetchUserProfile(session.user.id);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) fetchUserProfile(session.user.id);
      else setUserProfile(null);
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchUserProfile = async (userId: string) => {
    try {
      const { data } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (data) setUserProfile(data);
    } catch (error) {
      console.warn("User profile not found in DB.");
    }
  };

  // Persistência em LocalStorage (Fallback para Guest)
  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(sessions));
    }
  }, [sessions]);

  // Carregar dados iniciais
  useEffect(() => {
    if (!isAuthChecking) {
      if (session) {
        loadSessionsFromSupabase();
      } else {
        const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
        if (saved) {
          try {
            const parsed = JSON.parse(saved);
            if (parsed.length > 0) {
              setSessions(parsed);
              setCurrentSessionId(parsed[0].id);
              return;
            }
          } catch(e) {}
        }
        createNewChat();
      }
    }
  }, [session, isAuthChecking]);

  const loadSessionsFromSupabase = async () => {
    try {
      const { data } = await supabase
        .from('chat_sessions')
        .select('*')
        .eq('user_id', session.user.id)
        .order('last_modified', { ascending: false });

      if (data && data.length > 0) {
        setSessions(data);
        if (!currentSessionId) setCurrentSessionId(data[0].id);
      } else {
        createNewChat();
      }
    } catch (error) {
      createNewChat();
    }
  };

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: crypto.randomUUID(),
      title: 'Nova Estratégia',
      messages: [],
      lastModified: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setCurrentView('chat');
    if (window.innerWidth < 768) setIsSidebarOpen(false);

    if (session) {
      supabase.from('chat_sessions').insert({
        id: newSession.id,
        user_id: session.user.id,
        title: newSession.title,
        messages: newSession.messages,
        last_modified: newSession.lastModified
      }).then();
    }
  };

  const updateCurrentSession = (text: string, role: 'user' | 'model', options?: GeneratedOption[]) => {
    if (!currentSessionId) return;

    setSessions(prevSessions => {
      return prevSessions.map(s => {
        if (s.id === currentSessionId) {
          const newMsg: Message = {
            id: Math.random().toString(36).substr(2, 9),
            role,
            content: text,
            options,
            timestamp: Date.now()
          };

          let newTitle = s.title;
          if (s.messages.length === 0 && role === 'user') {
            newTitle = text.length > 30 ? text.substring(0, 30) + '...' : text;
          }

          const updated = {
            ...s,
            title: newTitle,
            messages: [...s.messages, newMsg],
            lastModified: Date.now()
          };

          if (session) {
            supabase.from('chat_sessions').upsert({
              id: updated.id,
              user_id: session.user.id,
              title: updated.title,
              messages: updated.messages,
              last_modified: updated.lastModified
            }).then();
          }

          return updated;
        }
        return s;
      });
    });
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setSessions([]);
    setCurrentSessionId(null);
    setUserProfile(null);
    localStorage.removeItem(LOCAL_STORAGE_KEY);
    window.location.reload();
  };

  if (isAuthChecking) return <div className="h-screen w-full flex items-center justify-center bg-[#0f172a] text-blue-400 font-bold animate-pulse">COPY TRAVEL PREMIUM...</div>;

  const currentSession = sessions.find(s => s.id === currentSessionId);

  return (
    <div className={`${darkMode ? 'dark' : ''} flex h-screen w-full bg-slate-900 text-white overflow-hidden`}>
      {isSidebarOpen && <div className="fixed inset-0 bg-black/60 z-20 md:hidden" onClick={() => setIsSidebarOpen(false)} />}

      <aside className={`fixed md:relative z-30 w-[280px] h-full bg-slate-950 border-r border-white/5 transform transition-transform duration-300 flex flex-col ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0 md:w-0 overflow-hidden'}`}>
        <div className="p-6 flex items-center justify-between">
           <div className="flex items-center gap-3">
             <div className="w-9 h-9 rounded-xl bg-blue-600 flex items-center justify-center shadow-lg shadow-blue-600/20">
               <span className="text-white font-black text-sm">CT</span>
             </div>
             <div>
               <span className="font-bold text-white block leading-none text-sm">Copy Travel</span>
               <span className="text-[10px] text-blue-400 font-black uppercase tracking-tighter">Premium VIP</span>
             </div>
           </div>
        </div>

        <div className="px-4 pb-4 space-y-2">
          <button onClick={createNewChat} className="w-full flex items-center gap-3 px-4 py-3 text-sm bg-blue-600 hover:bg-blue-500 text-white rounded-xl transition-all font-bold shadow-lg shadow-blue-600/10">
            <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" /></svg>
            Nova Estratégia
          </button>

          <button onClick={() => { setCurrentView('library'); if(window.innerWidth < 768) setIsSidebarOpen(false); }} className={`w-full flex items-center gap-3 px-4 py-3 text-sm rounded-xl transition-all font-bold ${currentView === 'library' ? 'bg-white/10 text-white' : 'text-slate-400 hover:bg-white/5'}`}>
            <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
            Scripts de Venda
