        </div>

        <div className="flex-1 overflow-y-auto px-4 py-2 space-y-1 scrollbar-thin">
          <div className="px-2 text-[10px] font-black text-slate-500 uppercase tracking-[2px] mb-3 mt-4">Histórico Recente</div>
          {sessions.map(s => (
