import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabase';
import { UserProfile } from '../types';

interface SettingsProps {
  session: any;
  userProfile: UserProfile | null;
  onProfileUpdate: (profile: UserProfile) => void;
}

const Settings: React.FC<SettingsProps> = ({ session, userProfile, onProfileUpdate }) => {
  const [fullName, setFullName] = useState('');
  const [agencyName, setAgencyName] = useState('');
  const [phone, setPhone] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  useEffect(() => {
    if (userProfile) {
      setFullName(userProfile.full_name || '');
      setAgencyName(userProfile.agency_name || '');
      setPhone(userProfile.phone || '');
    }
  }, [userProfile]);

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!session) {
      // Local Save for Guest
      const updates: UserProfile = {
        id: 'guest',
        full_name: fullName,
        agency_name: agencyName,
        phone: phone,
      };
      onProfileUpdate(updates);
      localStorage.setItem('guest_profile', JSON.stringify(updates));
      setMessage({ type: 'success', text: 'Perfil Guest salvo localmente!' });
      return;
    }

    setLoading(true);
    setMessage(null);

    try {
      const updates = {
        id: session.user.id,
        full_name: fullName,
        agency_name: agencyName,
        phone: phone,
        updated_at: new Date(),
      };

      const { error } = await supabase.from('profiles').upsert(updates);
      if (error) throw error;

      onProfileUpdate(updates);
      setMessage({ type: 'success', text: 'Dados atualizados na nuvem!' });
    } catch (error: any) {
      setMessage({ type: 'error', text: error.message || 'Erro ao atualizar dados.' });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!session && !userProfile) {
      const saved = localStorage.getItem('guest_profile');
      if (saved) {
        const parsed = JSON.parse(saved);
        setFullName(parsed.full_name || '');
        setAgencyName(parsed.agency_name || '');
        setPhone(parsed.phone || '');
      }
    }
  }, [session, userProfile]);

  return (
    <div className="flex-1 overflow-y-auto bg-slate-900 p-4 md:p-8">
      <div className="max-w-2xl mx-auto">
        <div className="mb-8">
          <h1 className="text-2xl font-bold text-white flex items-center gap-3">
            <span className="p-2 bg-blue-600/20 rounded-xl">⚙️</span>
            Configurações
          </h1>
          <p className="text-slate-400 mt-2 text-sm">
            Personalize como a IA deve se comportar e se identificar.
          </p>
        </div>

        <div className="bg-slate-800/50 backdrop-blur-xl rounded-[32px] border border-white/5 p-8 md:p-10 shadow-2xl">
          <form onSubmit={handleSave} className="space-y-8">

            {!session && (
              <div className="p-4 bg-blue-500/10 border border-blue-500/20 rounded-2xl text-blue-400 text-xs font-medium leading-relaxed">
                🚀 Você está em <strong>Modo Guest</strong>. Seus dados serão salvos apenas neste navegador.
              </div>
            )}

            <div className="grid md:grid-cols-2 gap-8">
              <div className="space-y-2">
                <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest ml-1">
                  Nome do Agente
                </label>
                <input
                  type="text"
                  value={fullName}
                  onChange={(e) => setFullName(e.target.value)}
                  placeholder="Seu Nome"
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition-all text-sm"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest ml-1">
                  Agência
                </label>
                <input
                  type="text"
                  value={agencyName}
                  onChange={(e) => setAgencyName(e.target.value)}
                  placeholder="Nome da Agência"
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition-all text-sm"
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest ml-1">
                WhatsApp de Suporte
              </label>
              <input
                type="tel"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                placeholder="(00) 00000-0000"
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition-all text-sm"
              />
            </div>

            {session && (
              <div className="pt-6 border-t border-white/5">
                <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest ml-1">
                  Conta Conectada
                </label>
                <div className="mt-2 text-sm text-slate-400 bg-white/5 px-5 py-4 rounded-2xl border border-white/5">
                  {session.user.email}
                </div>
              </div>
            )}

            {message && (
              <div className={`p-5 rounded-2xl flex items-center gap-3 text-sm font-bold animate-in fade-in slide-in-from-bottom-2 duration-300 ${
                message.type === 'success' 
                  ? 'bg-emerald-500/10 border border-emerald-500/20 text-emerald-400' 
                  : 'bg-red-500/10 border border-red-500/20 text-red-400'
              }`}>
                {message.type === 'success' ? '✓' : '✕'} {message.text}
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full py-5 bg-blue-600 hover:bg-blue-500 text-white font-black rounded-2xl transition-all shadow-xl shadow-blue-600/20 active:scale-[0.98] disabled:opacity-50 text-xs uppercase tracking-widest"
            >
              {loading ? 'Sincronizando...' : 'Atualizar Perfil Premium'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

