import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedOption, Message, UserProfile } from "../types";

const apiKey = process.env.API_KEY;
const ai = new GoogleGenAI({ apiKey: apiKey || '' });

export const generateChatResponse = async (
  currentInput: string,
  history: Message[],
  userProfile?: UserProfile | null
): Promise<{ text: string; options: GeneratedOption[] }> => {

  const conversationContext = history
    .slice(-4) // Foco no contexto imediato para manter a agilidade
    .map(msg => `${msg.role === 'user' ? 'Agente' : 'IA'}: ${msg.content}`)
    .join('\n');

  const agentName = userProfile?.full_name || 'especialista';

  const systemPrompt = `
    Você é o estrategista de vendas de elite de ${agentName}. Seu objetivo é converter leads de turismo via WhatsApp.

    DIRETRIZES DE ESCRITA PREMIUM:
    1. CURTO E DIRETO: Máximo 3 frases. Sem "parágrafos" pesados.
    2. TOM HUMANO: Use "Oi", "Poxa", "Entendo". Menos cara de robô, mais cara de amigo especialista.
    3. PSICOLOGIA DE PREÇOS: Nunca jogue o valor total de uma vez. Use "Apenas 12x de R$ X" ou "R$ X por dia de felicidade".
    4. TÉCNICA DO "OU/OU": Sempre ofereça duas opções positivas (ex: "Prefere voar de manhã ou à tarde?").
    5. OBRIGATÓRIO: Termine SEMPRE com uma pergunta poderosa que exige uma resposta rápida.
    6. VALOR vs PREÇO: Antes de falar o preço, mencione um benefício emocional (conforto, segurança, status).

    SCHEMA DE RESPOSTA (JSON):
    - analysis: Breve análise do estado emocional do cliente.
    - options: Lista com 3 variações baseadas em metodologias diferentes (ex: Cialdini, SPIN Selling, Chris Voss).
  `;

  const prompt = `
    Contexto: ${conversationContext}
    Fala do Cliente: "${currentInput}"

    Gere 3 scripts de alta conversão. Para cada um, explique a metodologia de persuasão utilizada para que o agente aprenda enquanto vende.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction: systemPrompt,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            analysis: { type: Type.STRING },
            options: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  content: { type: Type.STRING, description: "O script pronto para copiar" },
                  technique: { type: Type.STRING, description: "Nome da técnica" },
                  rationale: { type: Type.STRING, description: "Por que funciona?" },
                  methodology: { type: Type.STRING, description: "Explicação técnica para o agente aprender" },
                  source: { type: Type.STRING, description: "Referência (Ex: Robert Cialdini)" },
                  branches: {
                    type: Type.OBJECT,
                    properties: {
                      positive: { type: Type.STRING },
                      negative: { type: Type.STRING }
                    },
                    required: ["positive", "negative"]
                  }
                },
                required: ["content", "technique", "rationale", "methodology", "source", "branches"]
              }
            }
          }
        }
      }
    });

    const result = JSON.parse(response.text || "{}");
    return {
      text: result.analysis || "Análise da oportunidade:",
      options: result.options || []
    };
  } catch (error) {
    console.error("AI Error:", error);
    return { text: "Erro ao calibrar scripts. Tente novamente.", options: [] };
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Message, GeneratedOption, UserProfile } from '../types';
import { generateChatResponse } from '../services/gemini';

interface ChatInterfaceProps {
  messages: Message[];
  onSendMessage: (text: string, role: 'user' | 'model', options?: GeneratedOption[]) => void;
  isLoading: boolean;
  setLoading: (loading: boolean) => void;
  userProfile?: UserProfile | null;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  messages, 
  onSendMessage, 
  isLoading, 
  setLoading,
  userProfile
}) => {
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const handleSend = async () => {
    if (!inputText.trim() || isLoading) return;
    const text = inputText;
    setInputText('');
    onSendMessage(text, 'user');
    setLoading(true);
    try {
      const response = await generateChatResponse(text, messages, userProfile);
      onSendMessage(response.text, 'model', response.options);
    } catch (error) {
      onSendMessage("Ops, erro na conexão Premium.", 'model');
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  return (
    <div className="flex flex-col h-full bg-[#0f172a]">
      <div className="flex-1 overflow-y-auto p-4 md:p-8 scrollbar-thin">
        <div className="max-w-3xl mx-auto space-y-10 pb-20">

          {messages.length === 0 ? (
            <div className="flex flex-col items-center justify-center min-h-[50vh] text-center opacity-50">
              <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center mb-6 shadow-2xl">
                <span className="text-white font-bold text-2xl">CT</span>
              </div>
              <h2 className="text-xl font-bold text-white mb-2 tracking-tight">QG de Vendas Premium</h2>
              <p className="text-slate-400 text-sm max-w-xs">Cole aqui o que seu cliente disse. A IA vai te ensinar a fechar.</p>
            </div>
          ) : (
            messages.map((msg) => (
              <div key={msg.id} className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`w-full max-w-2xl flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>

                  <div className={`flex-shrink-0 w-8 h-8 rounded-lg flex items-center justify-center mt-1 ${
                    msg.role === 'user' ? 'bg-blue-600' : 'bg-white/10 border border-white/10'
                  }`}>
                    <span className="text-[10px] font-bold text-white">{msg.role === 'user' ? 'EU' : 'CT'}</span>
                  </div>

                  <div className="flex-1 min-w-0">
                    <div className={`text-sm py-3 px-4 rounded-2xl ${
                      msg.role === 'user' 
                        ? 'bg-blue-600 text-white rounded-tr-none' 
                        : 'text-slate-300 italic'
                    }`}>
