import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedOption, Message, UserProfile } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateChatResponse = async (
  currentInput: string,
  history: Message[],
  userProfile?: UserProfile | null
): Promise<{ text: string; options: GeneratedOption[] }> => {

  const conversationContext = history
    .slice(-5)
    .map(msg => `${msg.role === 'user' ? 'Agente' : 'Mentor'}: ${msg.content}`)
    .join('\n');

  const systemInstruction = `
    VOCÊ É UM MENTOR SENIOR EM NEUROVENDAS E FECHAMENTO DE TURISMO.
    Seu objetivo é transformar o agente ${userProfile?.full_name || ''} em uma máquina de vendas.

    DIRETRIZES DE OURO (ESTILO WHATSAPP):
    1. SCRIPTS CURTOS: Máximo 2 a 3 frases curtas. Use parágrafos que "escorregam" no olho.
    2. TOM PESSOAL: Acolhedor, amigável, como um consultor que se importa. Use "Poxa", "Entendo", "Imagine".
    3. VALOR > PREÇO: Nunca mande o preço seco. Sempre mencione o VALOR (entregáveis, paz, status) antes do PREÇO.
    4. PRECIFICAÇÃO PSICOLÓGICA: Use 12x de R$ 497 em vez de R$ 5.964. Use numerologia (finais 7 ou 9). Explique que o cérebro processa o valor da parcela como "barato".
    5. TÉCNICA OU/OU: Sempre termine com uma pergunta de dupla escolha (ex: "Prefere voar pela manhã ou tarde?").
    6. FECHAMENTO CONSTANTE: Toda fala deve impulsionar o cliente para a próxima etapa cronológica.

    FORMATO DE RESPOSTA (JSON):
    - analysis: Análise rápida da temperatura do cliente (Frio, Morno, Quente).
    - options: 3 variações baseadas em:
        1. Neuro-Persuasão (Cérebro Reptiliano/Segurança)
        2. Emoção Pura (Cérebro Límbico/Desejo)
        3. Negociação Direta (Chris Voss/Gatilhos de Perda)
  `;

  const prompt = `
    Contexto da Conversa:
    ${conversationContext}

    O que o cliente disse agora: "${currentInput}"

    Gere 3 opções de resposta de alta conversão. Para cada uma, inclua o campo 'methodology' ensinando ao agente qual técnica de persuasão foi usada e o campo 'psychologyTip' explicando por que essa estrutura ou preço funciona.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            analysis: { type: Type.STRING },
            options: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  content: { type: Type.STRING },
                  technique: { type: Type.STRING },
                  rationale: { type: Type.STRING },
                  methodology: { type: Type.STRING },
                  source: { type: Type.STRING },
                  psychologyTip: { type: Type.STRING },
                  branches: {
                    type: Type.OBJECT,
                    properties: {
                      positive: { type: Type.STRING },
                      negative: { type: Type.STRING }
                    },
                    required: ["positive", "negative"]
                  }
                },
                required: ["content", "technique", "rationale", "methodology", "source", "psychologyTip", "branches"]
              }
            }
          }
        }
      }
    });

    const result = JSON.parse(response.text || "{}");
    return {
      text: result.analysis || "Analizando a oportunidade...",
      options: result.options || []
    };
  } catch (error) {
    console.error("AI Error:", error);
    return { text: "Erro na calibragem premium. Tente novamente.", options: [] };
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Message, GeneratedOption, UserProfile } from '../types';
import { generateChatResponse } from '../services/gemini';

interface ChatInterfaceProps {
  messages: Message[];
  onSendMessage: (text: string, role: 'user' | 'model', options?: GeneratedOption[]) => void;
  isLoading: boolean;
  setLoading: (loading: boolean) => void;
  userProfile?: UserProfile | null;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  messages, 
  onSendMessage, 
  isLoading, 
  setLoading,
  userProfile
}) => {
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const handleSend = async () => {
    if (!inputText.trim() || isLoading) return;
    const text = inputText;
    setInputText('');
    onSendMessage(text, 'user');
    setLoading(true);
    try {
      const response = await generateChatResponse(text, messages, userProfile);
      onSendMessage(response.text, 'model', response.options);
    } catch (error) {
      onSendMessage("Erro na conexão premium.", 'model');
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  return (
    <div className="flex flex-col h-full bg-[#0f172a]">
      <div className="flex-1 overflow-y-auto p-4 md:p-6 scrollbar-thin">
        <div className="max-w-3xl mx-auto space-y-12 pb-32">

          {messages.length === 0 ? (
            <div className="flex flex-col items-center justify-center min-h-[50vh] text-center">
              <div className="w-16 h-16 bg-blue-600 rounded-[20px] flex items-center justify-center mb-6 shadow-2xl shadow-blue-500/20">
                <span className="text-white font-black text-2xl">CT</span>
