              <h2 className="text-2xl font-bold text-white mb-2">Mentor de Vendas Premium</h2>
              <p className="text-slate-500 text-sm max-w-sm">Cole a fala do cliente e aprenda a fechar usando neurociência aplicada.</p>
            </div>
          ) : (
            messages.map((msg) => (
              <div key={msg.id} className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`w-full max-w-2xl flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>

                  <div className={`flex-shrink-0 w-8 h-8 rounded-lg flex items-center justify-center mt-1 ${
                    msg.role === 'user' ? 'bg-blue-600' : 'bg-white/10'
                  }`}>
                    <span className="text-[10px] font-bold text-white">{msg.role === 'user' ? 'EU' : 'AI'}</span>
                  </div>

                  <div className="flex-1 min-w-0">
                    <div className={`text-[15px] leading-relaxed py-3 px-4 rounded-2xl ${
                      msg.role === 'user' 
                        ? 'bg-blue-600 text-white rounded-tr-none' 
                        : 'text-slate-400 italic'
                    }`}>
                      {msg.content}
                    </div>

                    {msg.options && (
                      <div className="mt-8 space-y-10">
                        {msg.options.map((option, idx) => (
                          <div key={idx} className="bg-white/5 border border-white/10 rounded-[32px] overflow-hidden shadow-2xl animate-in fade-in slide-in-from-bottom-4 duration-500">

                            {/* Header: Technique Label */}
                            <div className="px-6 py-4 bg-white/5 flex items-center justify-between border-b border-white/5">
                              <div className="flex items-center gap-2">
                                <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-pulse"></span>
                                <span className="text-[10px] font-black uppercase tracking-[2px] text-blue-400">{option.technique}</span>
                              </div>
                              <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Fonte: {option.source}</span>
                            </div>

                            <div className="p-6 md:p-8">
                              {/* The Script */}
