import React, { useState } from 'react';
import { SALES_TEMPLATES } from '../data/templates';

const TemplateLibrary: React.FC = () => {
  const [selectedCategory, setSelectedCategory] = useState(SALES_TEMPLATES[0].id);
  const [copiedIndex, setCopiedIndex] = useState<string | null>(null);

  const activeCategory = SALES_TEMPLATES.find(c => c.id === selectedCategory);

  const handleCopy = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopiedIndex(id);
    setTimeout(() => setCopiedIndex(null), 2000);
  };

  return (
    <div className="h-full flex flex-col md:flex-row bg-slate-900 overflow-hidden">
      {/* Categories Sidebar */}
      <div className="w-full md:w-72 bg-slate-950 border-r border-white/5 overflow-y-auto">
        <div className="p-6 border-b border-white/5">
          <h2 className="text-xl font-bold text-white">QG de Scripts</h2>
          <p className="text-[10px] text-blue-400 font-black uppercase tracking-[2px] mt-1 text-xs">Neuro-Persuasão</p>
        </div>
        <div className="p-3 space-y-1">
          {SALES_TEMPLATES.map((category) => (
            <button
              key={category.id}
              onClick={() => setSelectedCategory(category.id)}
              className={`w-full flex items-center gap-4 px-4 py-4 rounded-2xl text-sm font-bold transition-all ${
                selectedCategory === category.id
                  ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20'
                  : 'text-slate-400 hover:bg-white/5 hover:text-white'
              }`}
            >
              <span className="text-xl">{category.icon}</span>
              <span>{category.title}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-y-auto p-4 md:p-10 bg-[#0f172a] scrollbar-thin">
        <div className="max-w-4xl mx-auto">
          <div className="mb-10">
            <div className="flex items-center gap-4 mb-2">
              <span className="text-4xl">{activeCategory?.icon}</span>
              <h1 className="text-3xl font-bold text-white tracking-tight">
                {activeCategory?.title}
              </h1>
            </div>
            <p className="text-slate-400 text-sm max-w-2xl leading-relaxed">
              Estes scripts utilizam gatilhos de PNL e Neurovendas. Copie, adapte levemente e veja a conversão aumentar.
            </p>
          </div>

          <div className="grid gap-10">
            {activeCategory?.scripts.map((script, idx) => {
              const uniqueId = `${activeCategory.id}-${idx}`;
              return (
                <div key={idx} className="bg-slate-900 rounded-[32px] border border-white/10 shadow-2xl overflow-hidden group animate-in fade-in slide-in-from-bottom-4 duration-500">

                  {/* Script Header */}
                  <div className="px-8 py-5 bg-white/5 flex items-center justify-between border-b border-white/5">
                    <div className="flex items-center gap-3">
                      <span className="w-2 h-2 bg-blue-500 rounded-full animate-pulse"></span>
                      <h3 className="text-xs font-black text-blue-400 uppercase tracking-widest">{script.title}</h3>
                    </div>
                    <button
                      onClick={() => handleCopy(script.content, uniqueId)}
                      className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                        copiedIndex === uniqueId
                          ? 'bg-emerald-500 text-white'
                          : 'bg-white/5 text-slate-400 hover:bg-white/10 hover:text-white'
                      }`}
                    >
                      {copiedIndex === uniqueId ? 'Copiado!' : 'Copiar Script'}
                    </button>
                  </div>

                  <div className="p-8">
                    {/* Message Bubble Style */}
                    <div className="bg-blue-600/10 border border-blue-500/20 p-6 rounded-[24px] rounded-tl-none mb-8">
                      <p className="text-lg text-white font-medium leading-relaxed whitespace-pre-wrap">
                        {script.content}
                      </p>
                    </div>

                    {/* Mentorship Insight Block */}
                    <div className="bg-white/5 rounded-2xl border border-white/5 p-5">
                      <div className="flex items-start gap-4">
                        <div className="w-10 h-10 bg-blue-600/20 rounded-xl flex items-center justify-center flex-shrink-0 text-xl shadow-inner">🧠</div>
                        <div>
                          <h4 className="text-[11px] font-black text-blue-400 uppercase tracking-widest mb-2">Insight de Especialista</h4>
                          <p className="text-sm text-slate-400 leading-relaxed font-medium italic">
                            {script.learning}
                          </p>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

